var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"오르카? 물론 알고말고.","JPN":"オルカ？もちろん知っているとも。","ENG":"Orca? Of course I know about her.","TWN":"奧爾卡？我當然知道。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"복면을 쓴 거인이란 얘기가 있는가 하면, 찢어진 구속복을 걸친 광인이란 말도 있지.","JPN":"覆面マスクをした巨人って話もあれば、破れた拘束衣を着た狂人って話もある。","ENG":"Some say it's a masked giant, while others say it's a madman wearing a tattered straitjacket.","TWN":"有人說他是帶著面具的巨人，也有人說他是穿著破爛拘束服裝的瘋子。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"내가 봤던 오르카는 너랑 비슷한 여자애였어. ......좀 더 어렸던가?","JPN":"俺が見たオルカは、君と同じくらいの女の子だった。……いや、もう少し年下かな？","ENG":"But the Orca I saw was a girl like you. Perhaps a bit younger?","TWN":"我看到的奧爾卡是跟妳差不多的女孩子……可能比妳還小吧？"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"우리 형제들이 위기에 몰렸을 때, 홀연히 나타나서 혼자 침식체들을 찢어발기던데, 어찌나 살벌하던지.","JPN":"俺たち兄弟が危ない時に、忽然と現れて一人で侵食体を殺しまくったんだ。本当に恐ろしかったよ。","ENG":"When me and my brothers were in a pinch, she appeared out of nowhere and ripped apart all the C.O. on her own. It was terrifying.","TWN":"當時我和我兄弟被逼到了絕境，然後他突然出現，一個人把侵蝕體撕成了碎片，場面非常血腥。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그때 내가 느꼈던 감정은, 구원자를 만났다기 보단......","JPN":"あれは救世主というより……","ENG":"At the moment, I didn't feel like I'd met a savior.","TWN":"那時我的感覺是，比起救援者……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"또 다른 포식자를 만난 기분이었어.","JPN":"もう一人の捕食者だった。","ENG":"Rather, I felt like I ran into another predator.","TWN":"更像是遇到了一個捕食者。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"눈을 마주치는 순간 꼼짝도 할 수가 없었거든.","JPN":"目が合った瞬間、身動きが取れなかったからな。","ENG":"I couldn't even flinch when our eyes met.","TWN":"跟他眼神相交的瞬間，我的身體根本無法動彈。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIATHAN_RIVAL_NULL_NULL","text":{"KOREA":"그럼 그 애는 지금 어디에 있어?","JPN":"じゃあ、その子は今どこに？","ENG":"So where is she now?","TWN":"所以，那孩子現在在哪？"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"뭐, 오르카말야? 참나. 내가 그걸 어떻게 알아?","JPN":"え、オルカのことか？は！俺だって知らないよ。","ENG":"Who, Orca? Hah. How should I know?","TWN":"啥，你說奧爾卡？我怎麼知道？"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"......뭐, 그래도 확실한 건 침식체들이 들끓는 곳 한복판에 있을 거란 것 정도?","JPN":"……まあ、確かなのは侵食体がいる所にいるってことくらいかな？","ENG":"Well, one thing is for sure. She's probably in the middle of a C.O. swarm.","TWN":"……但能確定的是，她一定在一堆侵蝕體的正中央。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그야 당연하겠지.","JPN":"そりゃあ当然だ。","ENG":"It's pretty obvious.","TWN":"那是當然的吧。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"오르카가 선하다, 악하다... 이렇게 생겼다, 저렇게 생겼다...","JPN":"オルカはいいやつだ、悪いやつだ……、こんな外見だ、あんな外見だ……","ENG":"Orca is good, Orca is bad... It's a man, it's a girl...","TWN":"奧爾卡是善良，是邪惡……是那樣，或這樣……"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"주장이 분분하게 갈리긴 해도, 반드시 일치하는 두 가지 증언이 있거든.","JPN":"本当に色々な話があるが、必ず一致する二つの証言がある。","ENG":"There are multiple opinions about Orca, but there are two things that everybody agrees on.","TWN":"雖然眾說紛紜，可是有兩件事說法都是一致的。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"하나는 워치에서 뿜어져 나오는 소름 끼치는 붉은 빛.","JPN":"一つはウォッチが放つ、気味の悪い赤い光。","ENG":"One is the creepy red light coming from the Watch.","TWN":"一是能量環發著令人毛骨悚然的紅光。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그리고 또 다른 하나가 침식체를 향한 맹목적인 적개심.","JPN":"そしてもう一つは、侵食体に対する狂気的な敵意だ。","ENG":"And the other is the blind hostility towards all C.O.","TWN":"然後另一個，是對侵蝕體的盲目敵意。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"녀석은 사람이 사는 안전구역엔 얼씬도 안 할 거야. 거기엔 침식체가 없으니까.","JPN":"やつは、人が暮らす安全区域には近づかないはずだ。そこには侵食体がいないからな。","ENG":"Orca would never go near safe populated areas. Because there are no C.O. there.","TWN":"那傢伙應該不會在人類居住的安全地區，因為那裡沒有侵蝕體。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEVIATHAN_RIVAL_NULL_NULL","text":{"KOREA":"그게 끝? 하아, 결국 별 도움도 안 되는 정보였네.","JPN":"それだけ？はあ、大した情報じゃないじゃん。","ENG":"Is that it? *Sigh* So it was all useless information in the end.","TWN":"這樣就沒了？真是一點幫助都沒有的情報。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"어이쿠, 어딜 은근슬쩍 도망치려고 하시나. 아직 우리 본 용무가 안 끝났잖아?","JPN":"おい、どこへ行くんだ？まだ話は終わってないぜ？","ENG":"Whoa, where do you think you're going? We still have some unfinished business.","TWN":"唉呀，妳這是想偷偷逃去哪啊？我們的事情還沒解決呢。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};